{
  "name": "Bulletproof Directive",
  "description": "A universal quality assurance framework and directive generator for AI-generated applications."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Phase, ToastMessage } from './types';
import { PHASES } from './constants';
import { PhaseCard } from './components/PhaseCard';
import { ProgressBar } from './components/ProgressBar';
import { Toast } from './components/Toast';
import { Icons } from './components/Icons';

const App: React.FC = () => {
  const [completedPhases, setCompletedPhases] = useState<number[]>([]);
  const [expandedPhases, setExpandedPhases] = useState<number[]>([]);
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [toast, setToast] = useState<ToastMessage | null>(null);

  // Initialize theme
  useEffect(() => {
    document.documentElement.className = theme;
  }, [theme]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const copyToClipboard = async (text: string, phaseId: number, isAuto: boolean = false) => {
    try {
      await navigator.clipboard.writeText(text);
      const message = isAuto
        ? `Phase ${phaseId} directive ready!`
        : `Phase ${phaseId} directive copied!`;
      showToast(message, 'success');
    } catch (err) {
      showToast('Failed to copy to clipboard', 'error');
    }
  };

  const togglePhase = (phaseId: number) => {
    const isCurrentlyExpanded = expandedPhases.includes(phaseId);

    setExpandedPhases(prev =>
      prev.includes(phaseId)
        ? prev.filter(id => id !== phaseId)
        : [...prev, phaseId]
    );

    // Auto-copy on expand
    if (!isCurrentlyExpanded) {
      const phase = PHASES.find(p => p.id === phaseId);
      if (phase) {
        copyToClipboard(phase.directive, phase.id, true);
      }
    }
  };

  const toggleCompletion = (phaseId: number) => {
    setCompletedPhases(prev =>
      prev.includes(phaseId)
        ? prev.filter(id => id !== phaseId)
        : [...prev, phaseId]
    );
  };

  const resetProgress = () => {
    if (window.confirm("Are you sure you want to reset all progress?")) {
        setCompletedPhases([]);
        setExpandedPhases([]);
        showToast('Progress reset successfully', 'success');
    }
  };

  const expandAll = () => setExpandedPhases(PHASES.map(p => p.id));
  const collapseAll = () => setExpandedPhases([]);
  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const progress = (completedPhases.length / PHASES.length) * 100;

  return (
    <div className="min-h-screen relative font-sans selection:bg-accent-primary selection:text-white pb-20">
      {/* Noise Overlay */}
      <div className="fixed inset-0 opacity-[0.03] pointer-events-none z-0" 
           style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}>
      </div>

      <div className="relative z-10 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-12">

        {/* Header */}
        <header className="text-center mb-12 animate-slide-up">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-br from-accent-primary to-accent-secondary shadow-lg shadow-accent-primary/20 mb-6 transform transition-transform hover:scale-105">
            <span className="font-mono text-2xl font-bold text-white">BP</span>
          </div>
          <h1 className="font-mono text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-accent-primary to-accent-secondary mb-4 tracking-tight">
            Bulletproof Directive
          </h1>
          <p className="text-text-secondary text-lg max-w-2xl mx-auto font-serif">
            Universal Quality Assurance Framework for AI-Generated Applications
          </p>
          <div className="inline-flex items-center gap-2 mt-6 px-4 py-2 rounded-full bg-accent-primary/10 border border-accent-primary/20 text-accent-primary font-mono text-xs uppercase tracking-wider">
            <Icons.Lightbulb className="w-4 h-4" />
            <span>Click any phase to expand & auto-copy directive</span>
          </div>
        </header>

        {/* Controls */}
        <div className="bg-bg-secondary border border-border rounded-2xl p-6 mb-12 animate-fade-in shadow-xl backdrop-blur-sm bg-opacity-90">
          <div className="flex flex-col md:flex-row items-center gap-8">
            <div className="flex-1 w-full">
              <ProgressBar 
                progress={progress} 
                completedCount={completedPhases.length} 
                totalCount={PHASES.length} 
              />
            </div>
            <div className="flex flex-wrap justify-center gap-3 w-full md:w-auto">
              <ControlBtn onClick={expandAll} icon={<Icons.Maximize />} label="Expand All" />
              <ControlBtn onClick={collapseAll} icon={<Icons.Minimize />} label="Collapse" />
              <ControlBtn onClick={resetProgress} icon={<Icons.Refresh />} label="Reset" />
              <button 
                onClick={toggleTheme}
                className="p-3 rounded-xl bg-bg-tertiary border border-border text-text-primary hover:border-accent-primary hover:text-accent-primary transition-all duration-300 active:scale-95"
                title="Toggle Theme"
              >
                {theme === 'dark' ? <Icons.Sun /> : <Icons.Moon />}
              </button>
            </div>
          </div>
        </div>

        {/* Phase Grid */}
        <div className="grid gap-6">
          {PHASES.map((phase, idx) => (
            <div key={phase.id} className="animate-slide-up" style={{ animationDelay: `${idx * 100}ms` }}>
              <PhaseCard
                phase={phase}
                isExpanded={expandedPhases.includes(phase.id)}
                isCompleted={completedPhases.includes(phase.id)}
                onToggleExpand={() => togglePhase(phase.id)}
                onToggleComplete={() => toggleCompletion(phase.id)}
                onCopyDirective={() => copyToClipboard(phase.directive, phase.id)}
              />
            </div>
          ))}
        </div>

        {/* Footer */}
        <footer className="mt-20 pt-10 border-t border-border text-center text-text-muted pb-10">
          <p className="font-mono text-sm mb-2 text-text-primary">Universal QA Framework v1.0</p>
          <p className="text-sm">Ensuring production-grade quality for every deployment.</p>
        </footer>
      </div>

      {toast && <Toast message={toast.message} type={toast.type} />}
    </div>
  );
};

const ControlBtn: React.FC<{ onClick: () => void; icon: React.ReactNode; label: string }> = ({ onClick, icon, label }) => (
  <button
    onClick={onClick}
    className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-bg-tertiary border border-border text-text-primary text-sm font-mono font-medium hover:bg-bg-secondary hover:border-accent-primary transition-all duration-200 active:scale-95"
  >
    {React.cloneElement(icon as React.ReactElement, { className: "w-4 h-4" })}
    <span>{label}</span>
  </button>
);

export default App;

export interface Phase {
    id: number;
    title: string;
    description: string;
    tasks: string[];
    deliverables: string[];
    directive: string;
}

export interface ToastMessage {
    message: string;
    type: 'success' | 'error';
}

import React from 'react';
import { Phase } from '../types';
import { Icons } from './Icons';

interface PhaseCardProps {
    phase: Phase;
    isExpanded: boolean;
    isCompleted: boolean;
    onToggleExpand: () => void;
    onToggleComplete: () => void;
    onCopyDirective: () => void;
}

export const PhaseCard: React.FC<PhaseCardProps> = ({
    phase,
    isExpanded,
    isCompleted,
    onToggleExpand,
    onToggleComplete,
    onCopyDirective
}) => {
    // Dynamic color for the phase number
    const getPhaseColor = (id: number) => {
        const colors = {
            1: 'bg-phase-1',
            2: 'bg-phase-2',
            3: 'bg-phase-3',
            4: 'bg-phase-4',
            5: 'bg-phase-5'
        };
        return (colors as any)[id] || 'bg-accent-primary';
    };

    return (
        <div 
            className={`
                group rounded-2xl border transition-all duration-300 overflow-hidden
                ${isCompleted 
                    ? 'bg-bg-secondary border-green-500/50 shadow-[0_0_20px_rgba(16,185,129,0.1)]' 
                    : 'bg-bg-secondary border-border hover:border-accent-primary hover:shadow-[0_8px_32px_rgba(0,0,0,0.2)]'
                }
            `}
        >
            {/* Header */}
            <div 
                onClick={onToggleExpand}
                className="p-6 cursor-pointer flex items-center justify-between gap-4 select-none bg-gradient-to-br from-white/5 to-transparent hover:from-white/10 transition-colors"
            >
                <div className="flex items-center gap-6">
                    <div className={`
                        w-12 h-12 rounded-xl flex items-center justify-center text-white font-mono font-bold text-xl shadow-lg
                        ${getPhaseColor(phase.id)} transition-transform group-hover:scale-110 duration-300
                    `}>
                        {phase.id}
                    </div>
                    <div>
                        <h3 className="font-mono text-xl font-bold text-text-primary tracking-tight">
                            {phase.title}
                        </h3>
                        <p className="text-text-muted text-sm mt-1">{phase.description}</p>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                    <span className={`
                        px-3 py-1 rounded-lg font-mono text-xs font-medium uppercase tracking-wider
                        ${isCompleted 
                            ? 'bg-green-500/20 text-green-400' 
                            : 'bg-text-muted/20 text-text-muted'
                        }
                    `}>
                        {isCompleted ? '✓ Complete' : 'Pending'}
                    </span>
                    <div className={`transform transition-transform duration-300 text-text-muted ${isExpanded ? 'rotate-180' : ''}`}>
                        <Icons.ChevronDown />
                    </div>
                </div>
            </div>

            {/* Expanded Content */}
            <div className={`
                transition-all duration-500 ease-in-out
                ${isExpanded ? 'max-h-[2000px] opacity-100' : 'max-h-0 opacity-0'}
            `}>
                <div className="p-6 pt-0 border-t border-border/50">
                    <div className="mt-6 grid md:grid-cols-2 gap-8">
                        {/* Tasks */}
                        <div>
                            <h4 className="font-mono text-xs font-bold text-accent-primary uppercase tracking-widest mb-4">
                                Checklist
                            </h4>
                            <ul className="space-y-3">
                                {phase.tasks.map((task, i) => (
                                    <li key={i} className="flex items-start gap-3 p-3 rounded-lg bg-bg-tertiary/50 hover:bg-bg-tertiary transition-colors">
                                        <div className={`
                                            mt-0.5 w-5 h-5 rounded border-2 flex items-center justify-center transition-colors
                                            ${isCompleted ? 'bg-green-500 border-green-500' : 'border-border'}
                                        `}>
                                            {isCompleted && <Icons.Check className="w-3.5 h-3.5 text-white" />}
                                        </div>
                                        <span className={`text-sm ${isCompleted ? 'text-text-muted line-through' : 'text-text-secondary'}`}>
                                            {task}
                                        </span>
                                    </li>
                                ))}
                            </ul>
                        </div>

                        {/* Deliverables */}
                        <div>
                            <h4 className="font-mono text-xs font-bold text-accent-primary uppercase tracking-widest mb-4">
                                Deliverables
                            </h4>
                            <ul className="space-y-2">
                                {phase.deliverables.map((item, i) => (
                                    <li key={i} className="text-sm font-mono text-text-secondary pl-3 border-l-2 border-accent-secondary py-1 bg-bg-tertiary/30 rounded-r">
                                        {item}
                                    </li>
                                ))}
                            </ul>
                        </div>
                    </div>

                    {/* Actions */}
                    <div className="mt-8 flex flex-col sm:flex-row gap-4">
                        <button
                            onClick={(e) => { e.stopPropagation(); onCopyDirective(); }}
                            className="flex-1 py-3 px-4 rounded-xl bg-gradient-to-r from-accent-primary to-accent-secondary text-white font-mono text-sm font-bold uppercase tracking-wider hover:shadow-lg hover:shadow-accent-primary/25 hover:-translate-y-0.5 transition-all duration-200 flex items-center justify-center gap-2"
                        >
                            <Icons.Copy className="w-4 h-4" />
                            Copy Directive
                        </button>
                        <button
                            onClick={(e) => { e.stopPropagation(); onToggleComplete(); }}
                            className={`
                                flex-1 py-3 px-4 rounded-xl border font-mono text-sm font-bold uppercase tracking-wider transition-all duration-200 flex items-center justify-center gap-2
                                ${isCompleted 
                                    ? 'bg-transparent border-border text-text-muted hover:bg-bg-tertiary' 
                                    : 'bg-bg-tertiary border-border text-text-primary hover:border-green-500 hover:text-green-500'
                                }
                            `}
                        >
                            {isCompleted ? 'Mark Incomplete' : 'Mark Complete'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

