                            ? 'bg-accent-primary text-bg-primary shadow-lg shadow-accent-primary/25 scale-105' 
                            : 'bg-bg-tertiary border border-border text-text-secondary hover:border-accent-primary hover:text-text-primary'
                        }
                    `}
                >
                    {f}
                </button>
            ))}
        </div>

        {/* Phase Context Display */}
        <div className="max-w-4xl mx-auto mb-12 animate-fade-in" style={{ animationDelay: '150ms' }}>
          {expandedPhases.length > 0 ? (
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {expandedPhases.sort((a, b) => a - b).map(id => {
                const phase = PHASES.find(p => p.id === id);
                if (!phase) return null;
                return (
                  <div 
                    key={id} 
                    className="animate-slide-up p-4 rounded-xl bg-bg-secondary border border-border/50 shadow-sm flex flex-col gap-2 relative overflow-hidden group hover:border-accent-primary/50 transition-colors"
                  >
                    <div className={`absolute top-0 left-0 w-1 h-full ${getPhaseColorClass(id)} transition-all duration-300 group-hover:w-1.5`} />
