                                </div>
                                <div className="h-1.5 w-full bg-bg-tertiary rounded-full overflow-hidden">
                                    <div 
                                        className="h-full bg-accent-primary transition-all duration-300 ease-out"
                                        style={{ width: `${progress}%` }}
