import React, { useState, useEffect } from 'react';
import { Phase, ToastMessage } from './types';
import { PHASES } from './constants';
import { PhaseCard } from './components/PhaseCard';
import { ProgressBar } from './components/ProgressBar';
import { Toast } from './components/Toast';
import { Icons } from './components/Icons';
import { SRSModal } from './components/SRSModal';
import { Tooltip } from './components/Tooltip';
import { AIAssistant } from './components/AIAssistant';

const App: React.FC = () => {
  const [completedPhases, setCompletedPhases] = useState<number[]>([]);
  const [expandedPhases, setExpandedPhases] = useState<number[]>([]);
  const [theme, setTheme] = useState<'dark' | 'light' | 'high-contrast'>('dark');
  const [toast, setToast] = useState<ToastMessage | null>(null);
  const [showSRS, setShowSRS] = useState(false);
  const [filter, setFilter] = useState<'all' | 'completed' | 'pending'>('all');

  // AI Assistant Control
  const [assistantInput, setAssistantInput] = useState<string | undefined>(undefined);
  const [forceOpenAssistant, setForceOpenAssistant] = useState(false);

  // Initialize theme
  useEffect(() => {
    document.documentElement.className = theme;
  }, [theme]);

  const showToast = (message: string, type: 'success' | 'error' = 'success', action?: ToastMessage['action']) => {
    setToast({ message, type, action });
    // Keep toast longer if there is an action
    const duration = action ? 6000 : 3000;
    setTimeout(() => setToast(prev => prev?.message === message ? null : prev), duration);
  };

  const refineDirective = (text: string) => {
    setAssistantInput(`Can you help me refine this Phase Directive for better results?\n\n\`\`\`\n${text}\n\`\`\``);
    setForceOpenAssistant(true);
    // Reset triggers
    setTimeout(() => {
        setForceOpenAssistant(false);
    }, 100);
  };

  const copyToClipboard = async (text: string, phaseId: number, isAuto: boolean = false) => {
    try {
      await navigator.clipboard.writeText(text);
      const message = isAuto
        ? `Phase ${phaseId} directive ready!`
        : `Phase ${phaseId} directive copied!`;

      showToast(message, 'success', {
        label: 'Refine with AI',
        onClick: () => refineDirective(text)
      });
    } catch (err) {
      showToast('Failed to copy to clipboard', 'error');
    }
  };

  const togglePhase = (phaseId: number) => {
    const isCurrentlyExpanded = expandedPhases.includes(phaseId);

    setExpandedPhases(prev =>
      prev.includes(phaseId)
        ? prev.filter(id => id !== phaseId)
        : [...prev, phaseId]
    );

    // Auto-copy on expand
    if (!isCurrentlyExpanded) {
      const phase = PHASES.find(p => p.id === phaseId);
      if (phase) {
        copyToClipboard(phase.directive, phase.id, true);
      }
    }
  };

  const toggleCompletion = (phaseId: number) => {
    setCompletedPhases(prev =>
      prev.includes(phaseId)
        ? prev.filter(id => id !== phaseId)
        : [...prev, phaseId]
    );
  };

  const resetProgress = () => {
    if (window.confirm("Are you sure you want to reset all progress?")) {
        setCompletedPhases([]);
        setExpandedPhases([]);
        showToast('Progress reset successfully', 'success');
    }
  };

  const expandAll = () => setExpandedPhases(PHASES.map(p => p.id));
  const collapseAll = () => setExpandedPhases([]);

  const toggleTheme = () => {
    setTheme(prev => {
        if (prev === 'dark') return 'light';
        if (prev === 'light') return 'high-contrast';
        return 'dark';
    });
  };

  const getThemeIcon = () => {
    switch (theme) {
        case 'light': return <Icons.Sun />;
        case 'high-contrast': return <Icons.Contrast />;
        default: return <Icons.Moon />;
    }
  };

  const getThemeLabel = () => {
    switch (theme) {
        case 'light': return 'Light Mode';
        case 'high-contrast': return 'High Contrast';
        default: return 'Dark Mode';
    }
  };

  const getPhaseColorClass = (id: number) => {
    switch(id) {
        case 1: return 'bg-phase-1';
        case 2: return 'bg-phase-2';
        case 3: return 'bg-phase-3';
        case 4: return 'bg-phase-4';
        case 5: return 'bg-phase-5';
        default: return 'bg-accent-primary';
    }
  };

  const progress = (completedPhases.length / PHASES.length) * 100;

  const filteredPhases = PHASES.filter(phase => {
    if (filter === 'all') return true;
    const isCompleted = completedPhases.includes(phase.id);
    return filter === 'completed' ? isCompleted : !isCompleted;
  });

  return (
    <div className="min-h-screen relative font-sans selection:bg-accent-primary selection:text-white pb-20 overflow-x-hidden">
      {/* Noise Overlay */}
      <div className="fixed inset-0 opacity-[0.03] pointer-events-none z-0" 
           style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}>
      </div>

      <main className="relative z-10 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 pt-12">

        {/* Header */}
        <header className="text-center mb-8 animate-slide-up">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-br from-accent-primary to-accent-secondary shadow-lg shadow-accent-primary/20 mb-6 transform transition-transform hover:scale-105">
            <span className="font-mono text-2xl font-bold text-white">BP</span>
          </div>
          <h1 className="font-mono text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-accent-primary to-accent-secondary mb-4 tracking-tight">
            Bulletproof Directive
          </h1>
          <p className="text-text-secondary text-lg max-w-2xl mx-auto font-serif">
            Universal Quality Assurance Framework for AI-Generated Applications
          </p>
          <div className="flex justify-center gap-3 mt-6">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-accent-primary/10 border border-accent-primary/20 text-accent-primary font-mono text-xs uppercase tracking-wider">
                <Icons.Lightbulb className="w-4 h-4" />
                <span>Click any phase to expand</span>
             </div>
             <button 
                onClick={() => setShowSRS(true)}
                className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-bg-tertiary border border-border text-text-primary hover:border-accent-primary transition-colors font-mono text-xs uppercase tracking-wider"
             >
                <Icons.Copy className="w-4 h-4" />
                <span>View Specs</span>
             </button>
          </div>
        </header>

        {/* Filter Tabs */}
        <div className="flex justify-center gap-3 mb-8 animate-fade-in" style={{ animationDelay: '100ms' }}>
            {(['all', 'completed', 'pending'] as const).map((f) => (
                <button
                    key={f}
                    onClick={() => setFilter(f)}
                    className={`
                        px-5 py-2 rounded-full font-mono text-xs font-bold uppercase tracking-wider transition-all duration-300
                        ${filter === f 
                            ? 'bg-accent-primary text-bg-primary shadow-lg shadow-accent-primary/25 scale-105' 
                            : 'bg-bg-tertiary border border-border text-text-secondary hover:border-accent-primary hover:text-text-primary'
                        }
                    `}
                >
                    {f}
                </button>
            ))}
        </div>

        {/* Phase Context Display */}
        <div className="max-w-4xl mx-auto mb-12 animate-fade-in" style={{ animationDelay: '150ms' }}>
          {expandedPhases.length > 0 ? (
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {expandedPhases.sort((a, b) => a - b).map(id => {
                const phase = PHASES.find(p => p.id === id);
                if (!phase) return null;
                return (
                  <div 
                    key={id} 
                    className="animate-slide-up p-4 rounded-xl bg-bg-secondary border border-border/50 shadow-sm flex flex-col gap-2 relative overflow-hidden group hover:border-accent-primary/50 transition-colors"
                  >
                    <div className={`absolute top-0 left-0 w-1 h-full ${getPhaseColorClass(id)} transition-all duration-300 group-hover:w-1.5`} />
                    <div className="flex items-center gap-2 mb-1 pl-2">
                        <span className={`text-[10px] font-mono font-bold px-1.5 py-0.5 rounded text-white ${getPhaseColorClass(id)}`}>
                            PHASE {id}
                        </span>
                    </div>
                    <div className="pl-2">
                        <h4 className="text-xs font-bold text-text-primary truncate mb-1">{phase.title}</h4>
                        <p className="text-xs text-text-secondary leading-relaxed opacity-90">
                        {phase.description}
                        </p>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center p-6 border border-dashed border-border/40 rounded-xl bg-bg-tertiary/5 text-center">
                <Icons.Lightbulb className="w-5 h-5 text-text-muted mb-2 opacity-50" />
                <p className="text-sm text-text-muted font-mono">Select a phase below to view details here</p>
            </div>
          )}
        </div>

        {/* Controls */}
        <div className="bg-bg-secondary border border-border rounded-2xl p-6 mb-12 animate-fade-in shadow-xl backdrop-blur-sm bg-opacity-90" style={{ animationDelay: '200ms' }}>
          <div className="flex flex-col md:flex-row items-center gap-8">
            <div className="flex-1 w-full">
              <ProgressBar 
                progress={progress} 
                completedCount={completedPhases.length} 
                totalCount={PHASES.length} 
              />
            </div>
            <div className="flex flex-wrap justify-center gap-3 w-full md:w-auto">
              <ControlBtn 
                onClick={expandAll} 
                icon={<Icons.Maximize />} 
                label="Expand All" 
                tooltip="Open all phase cards to view full details"
              />
              <ControlBtn 
                onClick={collapseAll} 
                icon={<Icons.Minimize />} 
                label="Collapse" 
                tooltip="Close all phase cards to compact view"
              />
              <ControlBtn 
                onClick={resetProgress} 
                icon={<Icons.Refresh />} 
                label="Reset" 
                tooltip="Clear all progress and start over"
              />
              <Tooltip content={`Switch to ${theme === 'dark' ? 'Light' : theme === 'light' ? 'High Contrast' : 'Dark'} Mode`}>
                <button 
                  onClick={toggleTheme}
                  className="p-3 rounded-xl bg-bg-tertiary border border-border text-text-primary hover:border-accent-primary hover:text-accent-primary transition-all duration-300 active:scale-95 flex items-center gap-2"
                  title="Toggle Theme"
                  aria-label="Toggle Theme"
                >
                  {getThemeIcon()}
                  <span className="sr-only">{getThemeLabel()}</span>
                </button>
              </Tooltip>
            </div>
          </div>
        </div>

        {/* Phase Grid */}
        <div className="grid gap-6">
          {filteredPhases.length > 0 ? (
            filteredPhases.map((phase, idx) => (
                <div key={phase.id} className="animate-slide-up" style={{ animationDelay: `${idx * 100}ms` }}>
                <PhaseCard
                    phase={phase}
                    isExpanded={expandedPhases.includes(phase.id)}
                    isCompleted={completedPhases.includes(phase.id)}
                    onToggleExpand={() => togglePhase(phase.id)}
                    onToggleComplete={() => toggleCompletion(phase.id)}
                    onCopyDirective={() => copyToClipboard(phase.directive, phase.id)}
                    onRefineDirective={(text) => refineDirective(text)}
                />
                </div>
            ))
          ) : (
            <div className="text-center py-16 border-2 border-dashed border-border rounded-3xl animate-fade-in bg-bg-secondary/50">
                <div className="mb-4 inline-flex p-4 rounded-full bg-bg-tertiary text-text-muted">
                    <Icons.AlertCircle className="w-8 h-8" />
                </div>
                <p className="text-text-secondary font-mono text-lg">No {filter} phases found.</p>
                <button 
                    onClick={() => setFilter('all')}
                    className="mt-4 text-accent-primary hover:text-accent-secondary text-sm font-bold uppercase tracking-wider font-mono transition-colors"
                >
                    Clear Filter
                </button>
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="mt-20 pt-10 border-t border-border text-center text-text-muted pb-10">
          <p className="font-mono text-sm mb-2 text-text-primary">Universal QA Framework v1.0</p>
          <p className="text-sm">Ensuring production-grade quality for every deployment.</p>
        </footer>
      </main>

      {/* SRS Modal */}
      <SRSModal 
        isOpen={showSRS} 
        onClose={() => setShowSRS(false)} 
        completedPhases={completedPhases}
      />

      {/* AI Assistant Chat */}
      <AIAssistant 
        externalInput={assistantInput} 
        onInputConsumed={() => setAssistantInput(undefined)}
        forceOpen={forceOpenAssistant}
      />

      {toast && <Toast message={toast.message} type={toast.type} action={toast.action} />}
    </div>
  );
};

const ControlBtn: React.FC<{ onClick: () => void; icon: React.ReactNode; label: string; tooltip?: string }> = ({ onClick, icon, label, tooltip }) => (
  <Tooltip content={tooltip || label}>
    <button
