                                >
                                    {isRunning ? <Icons.Refresh className="w-4 h-4 animate-spin" /> : <Icons.Activity className="w-4 h-4" />}
                                    {isRunning ? 'Running Tests...' : 'Execute Test Suite'}
                                </button>
                            </div>

                            <div className="p-4 rounded-xl bg-bg-tertiary border border-border opacity-70">
                                <h3 className="font-bold text-text-primary mb-2">Puppeteer Integration</h3>
                                <p className="text-xs font-mono text-text-muted mb-2">tests/puppeteer/e2e.test.js</p>
                                <div className="bg-bg-primary p-3 rounded-lg border border-border text-[10px] font-mono text-text-secondary overflow-x-auto">
                                    <code>
                                        describe('App Startup', () ={'>'} {'{'}<br/>
                                        &nbsp;&nbsp;it('should load phase cards', async () ={'>'} {'{'}<br/>
                                        &nbsp;&nbsp;&nbsp;&nbsp;await page.goto('http://localhost:3000');<br/>
                                        &nbsp;&nbsp;&nbsp;&nbsp;await expect(page).toMatch('Bulletproof Directive');<br/>
                                        &nbsp;&nbsp;{'}'});<br/>
                                        {'}'});
                                    </code>
                                </div>
                            </div>
                        </div>

                        {/* Results */}
                        <div className="border border-border rounded-xl bg-bg-primary/50 overflow-hidden flex flex-col">
